const faqStart = content.indexOf("H2: Frequently Asked Questions");
const faqEnd = content.indexOf("H2: Organize Your PDF Now", faqStart);
const faqSchemaQuestions = Array.from(
  content.slice(faqStart, faqEnd).matchAll(/H3: ([^\n]+)\n([\s\S]*?)(?=\nH3: |\nH2:|$)/g),
).map((match) => [match[1], match[2].trim()] as const);

type SeoTable = { headers: string[]; rows: string[][] };

const organizeTable: SeoTable = {
  headers: ["Action", "Tool", "What It Does", "Pages Stay?"],
  rows: [
    ["Organize / Reorder", "Organize PDF (this page)", "Change the sequence of pages", "All pages - just reordered"],
    ["Remove / Delete", "Remove Pages", "Delete unwanted pages", "Remaining pages, resequenced"],
    ["Extract", "Extract Pages", "Copy chosen pages to a new file", "Original untouched"],
    ["Split", "Split PDF", "Break into multiple separate files", "Pages split across new files"],
    ["Merge", "Merge PDF", "Combine multiple PDFs into one", "All pages combined"],
  ],
};

function normalizeContent(source: string) {
  return source.replace(/(^|\n)(H[123]: [^\n]+)\n/g, "$1\n$2\n\n");
}

function renderInline(text: string): ReactNode[] {
  const routePattern = /((?:https?:\/\/)?(?:www\.)?repetigo\.com(?:\/[^\s.,;!?)]*)?|\/(?:tools|features|products|security|pricing|use-cases)\/[^\s.,;!?)]*)/gi;
  return text.split(routePattern).map((part, index) => {
    const href = mapRoute(part);
    if (href) return <a key={`${part}-${index}`} href={href}>{labelFor(href)}</a>;
    return part;
  });
}

function mapRoute(value: string) {
  const raw = value.trim().replace(/[.,;!?)]$/, "");
  if (!raw) return "";
  const clean = raw.replace(/^(?:https?:\/\/)?(?:www\.)?repetigo\.com/i, "").replace(/\/$/, "");
  const routes: Record<string, string> = {
    "": "/",
    "/tools/pdf": "/pdf-tools",
    "/tools/pdf/organize-pdf": "/pdf-tools/organize-pdf",
    "/tools/pdf/remove-pages": "/pdf-tools/remove-pages",
    "/tools/pdf/extract-pages": "/pdf-tools/extract-pages",
    "/tools/pdf/split-pdf": "/pdf-tools/split-pdf",
    "/tools/pdf/merge-pdf": "/pdf-tools/merge-pdf",
    "/products/printpilot": "/print-automation",
    "/security": "/privacy-policy",
    "/features/auto-delete": "/privacy-policy",
  };
  if (routes[clean]) return routes[clean];
  if (/^\/tools\/pdf\//.test(clean)) return `/pdf-tools/${clean.split("/")[3]}`;
  if (/^\/features\//.test(clean) || /^\/security/.test(clean)) return "/privacy-policy";
  if (/^\/products\//.test(clean) || /^\/use-cases\//.test(clean)) return "/print-automation";
  if (/^\/pricing/.test(clean)) return "/pricing";
  return "";
}

function labelFor(route: string) {
  const labels: Record<string, string> = {
    "/": "RepetiGo",
    "/pdf-tools": "Explore All PDF Tools",
    "/pdf-tools/organize-pdf": "Open Organize PDF",
    "/pdf-tools/remove-pages": "Open Remove Pages",
    "/pdf-tools/extract-pages": "Open Extract Pages",
    "/pdf-tools/split-pdf": "Open Split PDF",
    "/pdf-tools/merge-pdf": "Open Merge PDF",
    "/print-automation": "Learn About PrintPilot",
    "/privacy-policy": "Read Privacy Policy",
    "/pricing": "Start Free Trial",
  };
  return labels[route] || "Open PDF Tool";
}

function renderCta(line: string) {
  const label = line.replace(/^(?:➜|➤|→)\s*/, "").trim();
  const href = label.startsWith("See How PrintPilot") ? "/print-automation" : "/pdf-tools/organize-pdf";
  return <a className="tool-seo-inline-cta" href={href}>{label} <span>→</span></a>;
}

function renderTable(table: SeoTable) {
  return <div className="tool-seo-table-wrap"><table><thead><tr>{table.headers.map((header) => <th key={header}>{header}</th>)}</tr></thead><tbody>{table.rows.map((row) => <tr key={row.join("|")}>{row.map((cell, index) => <td key={`${cell}-${index}`}>{renderInline(cell)}</td>)}</tr>)}</tbody></table></div>;
}

function isCallout(line: string) {
  return /^(?:📊|💡|🔒|✅|⚠️)/.test(line);
}

function renderLines(lines: string[], keyPrefix: string) {
  const output: ReactNode[] = [];
  let index = 0;
  while (index < lines.length) {
    const line = lines[index];
    if (line.startsWith("✓")) {
      output.push(<div className="tool-seo-badges" key={`${keyPrefix}-badges-${index}`}>{line.split(/\s{2,}/).map((item) => <span key={item}>{item}</span>)}</div>);
      index += 1;
      continue;
    }
    if (isCallout(line)) {
      output.push(<aside className="tool-seo-callout" key={`${keyPrefix}-callout-${index}`}><p>{renderInline(line)}</p></aside>);
      index += 1;
      continue;
    }
    if (line.startsWith("•")) {
      const items: string[] = [];
      while (index < lines.length && lines[index].startsWith("•")) {
        items.push(lines[index].replace(/^•\s*/, ""));
        index += 1;
      }
      output.push(<ul className="tool-seo-list" key={`${keyPrefix}-list-${index}`}>{items.map((item) => <li key={item}>{renderInline(item)}</li>)}</ul>);
      continue;
    }
    if (/^(?:➜|➤|→)/.test(line)) {
      const ctas: string[] = [];
      while (index < lines.length && /^(?:➜|➤|→)/.test(lines[index])) {
        ctas.push(lines[index]);
        index += 1;
      }
      output.push(<div className="tool-seo-cta-stack" key={`${keyPrefix}-cta-${index}`}>{ctas.map((cta) => renderCta(cta))}</div>);
      continue;
    }
    output.push(<p key={`${keyPrefix}-paragraph-${index}`}>{renderInline(line)}</p>);
    index += 1;
  }
  return output;
}

function renderBlock(block: string, index: number): ReactNode {
  const lines = block.split("\n").map((line) => line.trim()).filter(Boolean);
  const first = lines[0];
  if (!first) return null;
  if (first.startsWith("H1: ")) return <h1 key={index}>{first.slice(4)}</h1>;
  if (first.startsWith("H2: ")) return <h2 key={index}>{first.slice(4)}</h2>;
  if (first.startsWith("H3: ")) return <h3 key={index}>{first.slice(4)}</h3>;

  const tableStart = lines.findIndex((line, lineIndex) => line === "Action" && lines.slice(lineIndex, lineIndex + 4).join("|") === "Action|Tool|What It Does|Pages Stay?");
  if (tableStart >= 0) {
    const tableEnd = tableStart + 4 + organizeTable.rows.length * 4;
    return <div key={index}>{tableStart > 0 ? <div className="tool-seo-copy-paragraph">{lines.slice(0, tableStart).map((line, lineIndex) => <p key={`${line}-${lineIndex}`}>{renderInline(line)}</p>)}</div> : null}{renderTable(organizeTable)}{lines.slice(tableEnd).map((line, lineIndex) => <p className="tool-seo-copy-paragraph" key={`${line}-after-${lineIndex}`}>{renderInline(line)}</p>)}</div>;
  }

  return <div className={index === 1 ? "tool-seo-copy-paragraph tool-seo-hero" : "tool-seo-copy-paragraph"} key={index}>{renderLines(lines, `${index}`)}</div>;
}

function StructuredSeoCopy({ source }: { source: string }) {
  const blocks = normalizeContent(source).split(/\n{2,}/).map((block) => block.trim()).filter(Boolean);
  return <>{blocks.map((block, index) => renderBlock(block, index))}</>;
}

function JsonLd() {
  const schemas = [
    {
      "@context": "https://schema.org",
      "@type": "SoftwareApplication",
      name: "RepetiGo Organize PDF",
      applicationCategory: "UtilitiesApplication",
      operatingSystem: "Web",
      offers: { "@type": "Offer", price: "0", priceCurrency: "INR" },
      description: "Free online PDF organizer for rearranging, reordering, and fixing PDF page order.",
    },
    {
      "@context": "https://schema.org",
      "@type": "HowTo",
      name: "How to Organize PDF Pages Online",
      step: [
        { "@type": "HowToStep", name: "Upload your PDF" },
        { "@type": "HowToStep", name: "Drag pages into order" },
        { "@type": "HowToStep", name: "Click Organize Pages" },
        { "@type": "HowToStep", name: "Download your PDF" },
      ],
    },
    {
      "@context": "https://schema.org",
      "@type": "FAQPage",
      mainEntity: faqSchemaQuestions.map(([question, answer]) => ({
        "@type": "Question",
        name: question,
        acceptedAnswer: { "@type": "Answer", text: answer },
      })),
    },
    {
      "@context": "https://schema.org",
      "@type": "BreadcrumbList",
      itemListElement: [
        { "@type": "ListItem", position: 1, name: "Home", item: "https://repetigo.com/" },
        { "@type": "ListItem", position: 2, name: "Tools", item: "https://repetigo.com/tools/" },
        { "@type": "ListItem", position: 3, name: "PDF Tools", item: "https://repetigo.com/tools/pdf/" },
        { "@type": "ListItem", position: 4, name: "Organize PDF", item: pageUrl },
      ],
    },
  ];
  return <>{schemas.map((schema) => <script key={schema["@type"]} type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(schema) }} />)}</>;
}

export default function OrganizeSeoContent() {
  return <><JsonLd /><article className="tool-seo-content" id="organize-pdf-guide"><StructuredSeoCopy source={content} /></article></>;
}
